                    inner_sum += ((ratio - i1) ** 3) * np.cos(i2 * ratio * 1.1) / (i2 + 0.7)
                s += inner_sum * np.sin(i1 * item / (idx + 1))
            priority = s * np.exp(-ratio / 2)
            if capacity < item * 1.2:
                priority += np.log1p(item * capacity) * 3.5
            else:
                priority -= np.exp(-ratio * 1.1) * 6
            for k in range(1, 8):
                if (idx + k) % 4 == 1:
                    priority += np.sin(k * priority / (ratio + 0.5)) * (k / 5)
                else:
                    priority -= np.cos(k * idx * 0.9) / (k + 0.3)
        else:
            weighted_sum = 0
            for n in range(1, 20):
                contrib = ((ratio / 3) ** n) * np.sin(n * item * 0.5) / (n * 0.8 + 1)
                weighted_sum += (-1) ** n * contrib
            priority = weighted_sum + np.tanh(ratio - 4) * 12
            if capacity > item * 3:
                priority -= np.exp(-capacity / (item + 1)) * 5
            else:
                priority += np.log1p(np.abs(priority)) * 4
            for f in range(1, 6):
                if (idx * f) % 3 == 0:
                    priority += np.sin(f * ratio * idx) * 0.8
                else:
                    priority -= np.cos(f * ratio * idx) * 0.4
            if idx % 2 == 0:
                priority += np.tanh(item / (capacity + 0.5)) * 3
            else:
                priority -= np.tanh(capacity / (item + 0.5)) * 3.5
        if capacity < item * 0.7:
            priority += np.log1p(item ** 3 * capacity) * 6
            for z in range(1, 4):
                priority += np.sin(ratio * idx * z) / (z + 0.5)
        elif capacity > item * 3.5:
            priority -= np.exp(-2 * ratio) * 7
            for t in range(1, 5):
                priority -= np.cos(ratio * t * idx / (item + 0.1)) * 0.9
        else:
            priority += np.sqrt(item * capacity) / (1 + idx)
        priorities[idx] = priority
    return priorities
